-- PHASE 1 Migration: Flat lab_results → LabResult[] array\n-- Run: sqlite3 db.db < db/lab-results-migration.sql\n\n-- Step 1: Safety check - only migrate if legacy data exists and array is null\nUPDATE Shipments \nSET lab_results_array = NULL \nWHERE lab_results IS NOT NULL \n  AND (lab_results_array IS NULL OR lab_results_array = 'null');\n\n-- Step 2: Transform legacy flat object to LabResult[]\n-- Note: Assumes legacy format {hazard_name: value_number}\nUPDATE Shipments \nSET lab_results_array = (\n  SELECT json_group_array(\n    json_object(\n      'testType', hazard_key,\n      'result', CASE WHEN hazard_value <= 0.02 THEN 'PASS' ELSE 'FAIL' END,\n      'value', hazard_value,\n      'unit', 'ppm',\n      'accredited', 1,\n      'labName', 'Migrated',\n      'testDate', datetime('now')\n    )\n  ) FROM (\n    SELECT \n      json_extract(lab_results, '$.' || j.key) as hazard_value,\n      j.key as hazard_key\n    FROM Shipments s2,\n    json_each(s2.lab_results) j\n    WHERE s2.id = Shipments.id\n      AND json_valid(s2.lab_results)\n  ) WHERE json_extract(lab_results, '$.' || hazard_key) IS NOT NULL\n) \nWHERE lab_results IS NOT NULL \n  AND json_valid(lab_results)\n  AND lab_results_array IS NULL;\n\n-- Step 3: Validate migration\nSELECT \n  id,\n  json_valid(lab_results_array) as array_valid,\n  json_array_length(lab_results_array) as result_count\nFROM Shipments \nWHERE lab_results IS NOT NULL;\n\n-- Step 4: Mark migrated (add metadata)\nUPDATE Shipments \nSET updated_at = CURRENT_TIMESTAMP,\n    evaluation_errors = json_set(COALESCE(evaluation_errors, '{}'), '$.migrationStatus', 'PHASE1_LAB_ARRAY_MIGRATED')\nWHERE lab_results_array IS NOT NULL \n  AND json_extract(lab_results, '$.aflatoxin') IS NOT NULL;  -- Example check\n\n-- Migration complete. Verify with: SELECT * FROM Shipments LIMIT 5;
